+    /// Model name to pricing mapping (normalized lowercase).
+    models: HashMap<String, ModelPricing>,
+    /// When this pricing data became effective.
+    pub effective_date: DateTime<Utc>,
+}
+
+impl Default for PricingTable {
+    fn default() -> Self {
