+fn sort_logs_by_mtime(entries: &mut [SessionLogPath]) {
+    entries.sort_by(|a, b| {
+        let by_time = b.modified_at.cmp(&a.modified_at);
+        if by_time == std::cmp::Ordering::Equal {
+            a.path.cmp(&b.path)
+        } else {
+            by_time
+        }
+    });
+}
